#include <stdio.h>

int main() {
    int age = 30;

    // Create a pointer and store the ADDRESS of age
    int *ptr = &age;

    printf("Age value: %d\n", age);
    printf("Pointer holds address: %p\n", ptr);
    return 0;
}

#include <stdio.h>

int main() {
    int age = 30;
    int *ptr = &age;

    // Read the value by following the pointer
    printf("Following ptr finds: %d\n", *ptr);

    // Change the value by following the pointer!
    *ptr = 99;
    printf("Age is now: %d\n", age); // Age itself changed!
    return 0;
}
